import httpx
from typing import Any, Callable, Awaitable
import asyncio

class ApiClient:
    def __init__(self, base_url: str, max_retries: int = 3):
        self.base_url = base_url
        self.client = httpx.AsyncClient()
        self.max_retries = max_retries

    async def _with_retry(self, func: Callable[..., Awaitable[Any]], *args, **kwargs) -> Any:
        delay = 1.0
        last_exception = None
        for attempt in range(self.max_retries + 1):
            try:
                return await func(*args, **kwargs)
            except httpx.HTTPStatusError as e:
                if not (500 <= e.response.status_code < 600):
                    raise
                last_exception = e
            except httpx.ConnectError as e:
                last_exception = e

            if attempt < self.max_retries:
                await asyncio.sleep(delay)
                delay *= 2
        raise last_exception

    async def get(self, endpoint: str) -> dict[str, Any]:
        async def _get():
            response = await self.client.get(f"{self.base_url}{endpoint}")
            response.raise_for_status()
            return response.json()
        return await self._with_retry(_get)

    async def post(self, endpoint: str, data: dict) -> dict[str, Any]:
        async def _post():
            response = await self.client.post(f"{self.base_url}{endpoint}", json=data)
            response.raise_for_status()
            return response.json()
        return await self._with_retry(_post)
