        state.progress.offset.toDp()
    })
    var prev by remember { mutableStateOf(Offset(0f, 0f)) }
    var prevOffsetAngle by remember { mutableStateOf(0f) }
    var offsetAngle by remember { mutableStateOf(0f) }
