        check(rg2Items[2].isSelected)
        check(rg2Items.filterIndexed { index, _ -> index != 2 }.all { !it.isSelected })

        check(rg1Items[1].isSelected)
        check(rg1Items.filterIndexed { index, _ -> index != 1 }.all { !it.isSelected })
